public static UniTask<T[]> WhenAll<T>(params UniTask<T>[] tasks)
        {
            if (tasks.Length == 0)
            {
                return UniTask.FromResult(Array.Empty<T>());
            }

            return new UniTask<T[]>(new WhenAllPromise<T>(tasks, tasks.Length), 0);
        }

