internal TResult Function(TParameter1 arg1, TParameter2 arg2)
    {
        var args = new Args(arg1, arg2);

        // Stryker disable once all
        if (_values.TryGetValue(args, out var result))
        {
            return result.Value;
        }

        return _values.GetOrAdd(args, new Lazy<TResult>(() => _function(arg1, arg2))).Value;
    }

public async Task CleanupDefunctSiloEntries(DateTimeOffset beforeDate)
        {
            var entriesList = (await FindAllSiloEntries())
                .Where(entry => !string.Equals(SiloInstanceTableEntry.TABLE_VERSION_ROW, entry.Item1.RowKey)
                    && entry.Item1.Status != INSTANCE_STATUS_ACTIVE
                    && entry.Item1.Timestamp < beforeDate)
                .ToList();

            await DeleteEntriesBatch(entriesList);
        }

public Task<Immutable<string[]>> GetGrainTypes(string[] exclusions)
    {
        return Task.FromResult(_typeManifestOptions.InterfaceImplementations
            .Where(s => s.GetInterfaces().Any(i => i == typeof(IGrain) || i == typeof(ISystemTarget)))
            .Where(s => exclusions == null || !exclusions.Any(e => s.FullName.StartsWith(e, StringComparison.OrdinalIgnoreCase)))
            .Select(s => s.FullName)
            .ToArray()
            .AsImmutable());
    }

public void Add(T item)
    {
        var newIndex = (_startIndex + Count) % _items.Length;

        _items[newIndex] = item;

        if (Count < _items.Length)
        {
            Count++;
        }
        else
        {
            _startIndex++;
        }
    }

private static string[] SanitizeExclusionFilters(string[] filters)
    {
        return (filters == null || filters.Length == 0) ? [] : [.. filters
            .Select(f => f.Trim())
            .Where(f => !string.IsNullOrWhiteSpace(f))
            .Select(f => string.Concat(f, '.'))];
    }

